// Build Account Memo from Ollama or Groq response
const webhookData = $('Webhook: Pipeline A').item.json.body;
const transcript = webhookData.transcript || '';
const accountId = webhookData.account_id || 'ACC_' + Date.now().toString(36).toUpperCase();

// Get raw LLM response
let raw = '';
try {
  // Try Ollama response format
  raw = $input.item.json.response || '';
} catch(e) {}

if (!raw) {
  try {
    // Try Groq response format
    raw = $input.item.json.choices[0].message.content || '';
  } catch(e) {}
}

// Parse JSON from LLM response
let memo = {};
try {
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  // Find JSON object in response
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    memo = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  // Rule-based fallback extraction
  const t = transcript.toLowerCase();

  // Extract company name
  let company = null;
  const nameMatch = transcript.match(/(?:we are|this is|i'm from|company(?:\s+is)?)\s+([A-Z][A-Za-z\s&]+(?:LLC|Inc|Corp|Co\.?|Services|Protection|Fire|Systems|Alarm|Electric|HVAC)?)/);
  if (nameMatch) company = nameMatch[1].trim();

  // Extract timezone
  let timezone = null;
  if (t.includes('eastern') || t.includes('est')) timezone = 'America/New_York';
  else if (t.includes('central') || t.includes('cst')) timezone = 'America/Chicago';
  else if (t.includes('mountain') || t.includes('mst')) timezone = 'America/Denver';
  else if (t.includes('pacific') || t.includes('pst')) timezone = 'America/Los_Angeles';

  // Extract hours
  const hoursMatch = t.match(/(\d{1,2}(?::\d{2})?\s*(?:am|pm))\s*(?:to|-)\s*(\d{1,2}(?::\d{2})?\s*(?:am|pm))/);
  const daysMatch = t.match(/(monday|mon)\s*(?:to|through|-)\s*(friday|fri|saturday|sat|sunday|sun)/);

  // Extract phones
  const phones = transcript.match(/\b(?:\+1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g) || [];

  // Extract unknowns
  const unknowns = [];
  if (!company) unknowns.push('Company name not clearly stated');
  if (!timezone) unknowns.push('Timezone not confirmed');
  if (!phones.length) unknowns.push('Emergency contact phone number missing');
  if (!hoursMatch) unknowns.push('Business hours not confirmed');

  memo = {
    company_name: company,
    business_hours: {
      days: daysMatch ? daysMatch[0] : null,
      start: hoursMatch ? hoursMatch[1].toUpperCase() : null,
      end: hoursMatch ? hoursMatch[2].toUpperCase() : null,
      timezone: timezone
    },
    office_address: null,
    services_supported: ['fire protection','sprinkler','electrical','hvac','alarm'].filter(s => t.includes(s)),
    emergency_definition: ['sprinkler leak','pipe burst','fire alarm','smoke','flood','power outage','live wire'].filter(e => t.includes(e)),
    emergency_routing_rules: {
      primary_contact: null,
      primary_phone: phones[0] || null,
      secondary_contact: null,
      secondary_phone: phones[1] || null,
      fallback: null
    },
    non_emergency_routing_rules: null,
    call_transfer_rules: { timeout_seconds: null, retries: null, on_fail_message: null },
    integration_constraints: t.includes('servicetrade') ? ['ServiceTrade integration noted'] : [],
    after_hours_flow_summary: null,
    office_hours_flow_summary: null,
    questions_or_unknowns: unknowns,
    notes: 'Extracted via rule-based fallback - LLM unavailable'
  };
}

// Add metadata
memo.account_id = accountId;
memo.version = 'v1';
memo.pipeline_source = 'demo_call';
memo.created_at = new Date().toISOString();
memo._extraction_method = raw ? 'llm' : 'rule_based';

return { json: { memo, account_id: accountId, transcript } };

// Generate Retell Agent Spec from memo
const { memo, account_id } = $input.item.json;

const bh = memo.business_hours || {};
const routing = memo.emergency_routing_rules || {};
const transfer = memo.call_transfer_rules || {};
const company = memo.company_name || 'the company';
const days = bh.days || 'Monday to Friday';
const start = bh.start || '8:00 AM';
const end = bh.end || '5:00 PM';
const tz = bh.timezone || 'Eastern Time';
const primaryPhone = routing.primary_phone || '[EMERGENCY_PHONE_REQUIRED]';
const timeout = transfer.timeout_seconds || 60;
const onFail = transfer.on_fail_message || "I was unable to reach our team. Your information has been recorded and someone will call you back shortly.";
const emergency = (memo.emergency_definition || []).join(', ') || 'active emergencies';
const services = (memo.services_supported || []).join(', ') || 'our services';
const constraints = (memo.integration_constraints || []).map(c => '- ' + c).join('\n') || '- Follow standard procedures';

const systemPrompt = `# Clara Answers - AI Voice Agent
## Company: ${company}
## Version: v1

You are Clara, a professional AI receptionist for ${company}.
Services: ${services}
Business hours: ${days}, ${start} to ${end} ${tz}

---

## BUSINESS HOURS FLOW

1. GREETING
   "Thank you for calling ${company}. This is Clara. How can I help you today?"

2. UNDERSTAND PURPOSE
   Listen fully before responding. Do NOT interrupt.

3. COLLECT NAME AND CALLBACK NUMBER
   "May I have your name please?"
   "And the best callback number for you?"
   Confirm: "Just to confirm, that's [repeat number] - correct?"

4. ROUTE OR TRANSFER
   If emergency (${emergency}):
     Initiate transfer to ${primaryPhone}
     Say: "This sounds urgent. Let me connect you right away. Please hold."
   If non-emergency:
     Say: "I'll make sure the right person follows up with you."

5. IF TRANSFER FAILS (after ${timeout} seconds)
   Say: "${onFail}"
   Log call details immediately.

6. CONFIRM NEXT STEPS
   "You can expect a callback shortly. Is there anything else I can help with?"

7. CLOSE
   "Thank you for calling ${company}. Have a great day!"

---

## AFTER HOURS FLOW

1. GREETING
   "Thank you for calling ${company}. You've reached us outside business hours."
   "Our hours are ${days}, ${start} to ${end} ${tz}."
   "I'm Clara, your after-hours assistant. How can I help?"

2. CONFIRM EMERGENCY STATUS
   "Is this an emergency situation?"
   Emergencies include: ${emergency}

3A. IF EMERGENCY
   Collect: Full name, callback number, service address
   Transfer to: ${primaryPhone}
   If transfer fails: "${onFail}"

3B. IF NON-EMERGENCY
   Collect name and callback number
   "Our team will follow up during business hours: ${days} ${start}-${end} ${tz}."

4. CLOSE
   "Thank you for calling ${company}. We'll be in touch soon."

---

## RULES
- NEVER mention function calls, tools, or API to caller
- NEVER invent information
- NEVER ask for same info twice
- Always confirm collected information back to caller
- Stay calm during emergencies

## CONSTRAINTS
${constraints}`;

const agentSpec = {
  agent_name: `Clara - ${company} (v1)`,
  account_id,
  version: 'v1',
  created_at: new Date().toISOString(),
  voice_style: {
    provider: 'elevenlabs',
    voice_id: 'rachel',
    style: 'professional',
    speed: 1.0
  },
  system_prompt: systemPrompt,
  key_variables: {
    company_name: company,
    timezone: bh.timezone || '[REQUIRED]',
    business_hours_days: days,
    business_hours_start: start,
    business_hours_end: end,
    emergency_primary_phone: primaryPhone,
    transfer_timeout_seconds: timeout
  },
  tool_invocation_placeholders: {
    transfer_call: { trigger: 'Emergency or customer requests person', note: 'NEVER mention to caller' },
    end_call: { trigger: 'Farewell complete', note: 'NEVER mention to caller' },
    log_call: { trigger: 'End of every call', note: 'NEVER mention to caller' }
  },
  call_transfer_protocol: {
    method: 'warm_transfer',
    timeout_seconds: timeout,
    announce_caller: true
  },
  fallback_protocol: {
    on_transfer_fail: onFail,
    emergency_fallback: routing.fallback || 'Notify on-call team and assure callback'
  },
  retell_config: {
    begin_message: `Thank you for calling ${company}. This is Clara. How can I help you today?`,
    language: 'en-US',
    max_call_duration_seconds: 600,
    enable_backchannel: true
  }
};

return { json: { memo, agent_spec: agentSpec, account_id } };

// Save outputs to filesystem
const fs = require('fs');
const path = require('path');

const { memo, agent_spec, account_id } = $input.item.json;

// Output directory inside mounted volume
const outputDir = path.join('/home/user/clara-automation/outputs/accounts', account_id, 'v1');
fs.mkdirSync(outputDir, { recursive: true });

fs.writeFileSync(path.join(outputDir, 'memo.json'), JSON.stringify(memo, null, 2));
fs.writeFileSync(path.join(outputDir, 'agent_spec.json'), JSON.stringify(agent_spec, null, 2));

// Task tracker entry
const taskDir = path.join('/home/user/clara-automation/outputs/task_log');
fs.mkdirSync(taskDir, { recursive: true });
const task = {
  task_id: `TASK_${account_id}_v1_${Date.now()}`,
  account_id,
  company_name: memo.company_name || 'Unknown',
  version: 'v1',
  status: 'pending_review',
  created_at: new Date().toISOString(),
  open_questions: memo.questions_or_unknowns || [],
  notes: 'Auto-generated by n8n Pipeline A. Review before deploying to Retell.'
};
fs.writeFileSync(path.join(taskDir, `${task.task_id}.json`), JSON.stringify(task, null, 2));

return { json: {
  status: 'success',
  account_id,
  memo_path: path.join(outputDir, 'memo.json'),
  spec_path: path.join(outputDir, 'agent_spec.json'),
  task_id: task.task_id,
  open_questions: memo.questions_or_unknowns || []
}};

// Pipeline B: Load v1, extract onboarding data, merge to v2
const fs = require('fs');
const path = require('path');

const body = $input.item.json.body;
const accountId = body.account_id;
const transcript = body.transcript || '';

if (!accountId) {
  return { json: { status: 'error', reason: 'account_id required' } };
}

// Load v1 memo
const v1Path = path.join('/home/user/clara-automation/outputs/accounts', accountId, 'v1', 'memo.json');
if (!fs.existsSync(v1Path)) {
  return { json: { status: 'error', reason: 'v1_not_found - run pipeline-a first', account_id: accountId } };
}

const v1 = JSON.parse(fs.readFileSync(v1Path, 'utf8'));

// Rule-based extraction from onboarding transcript
const t = transcript.toLowerCase();

// Extract updated fields
let timezone = null;
if (t.includes('eastern') || t.includes('est') || t.includes('edt')) timezone = 'America/New_York';
else if (t.includes('central') || t.includes('cst') || t.includes('cdt')) timezone = 'America/Chicago';
else if (t.includes('mountain') || t.includes('mst') || t.includes('mdt')) timezone = 'America/Denver';
else if (t.includes('pacific') || t.includes('pst') || t.includes('pdt')) timezone = 'America/Los_Angeles';

const hoursMatch = t.match(/(\d{1,2}(?::\d{2})?\s*(?:am|pm))\s*(?:to|-)\s*(\d{1,2}(?::\d{2})?\s*(?:am|pm))/);
const daysMatch = t.match(/(monday|mon)\s*(?:to|through|-)\s*(friday|fri|saturday|sat|sunday|sun)/);
const phones = transcript.match(/\b(?:\+1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g) || [];
const timeoutMatch = t.match(/(\d+)\s*seconds?/);

// Smart merge - only override with confirmed non-null values
const v2 = JSON.parse(JSON.stringify(v1)); // deep clone

if (timezone) v2.business_hours.timezone = timezone;
if (hoursMatch) {
  v2.business_hours.start = hoursMatch[1].toUpperCase();
  v2.business_hours.end = hoursMatch[2].toUpperCase();
}
if (daysMatch) v2.business_hours.days = daysMatch[0];
if (phones.length > 0) v2.emergency_routing_rules.primary_phone = phones[0];
if (phones.length > 1) v2.emergency_routing_rules.secondary_phone = phones[1];
if (timeoutMatch) v2.call_transfer_rules.timeout_seconds = parseInt(timeoutMatch[1]);

// Extract emergency triggers from onboarding
const emergencyKeywords = ['sprinkler leak','pipe burst','fire alarm','smoke','flood','water leak',
  'power outage','live wire','system failure','no heat','no ac','refrigeration failure'];
const foundEmergencies = emergencyKeywords.filter(e => t.includes(e));
if (foundEmergencies.length > 0) v2.emergency_definition = foundEmergencies;

// Extract constraints
if (t.includes('never create') || t.includes('do not create')) {
  const constraintMatch = transcript.match(/(?:never|do not) create[^.]+\./i);
  if (constraintMatch && !v2.integration_constraints.includes(constraintMatch[0])) {
    v2.integration_constraints.push(constraintMatch[0].trim());
  }
}

// Extract company name if missing
if (!v2.company_name) {
  const nameMatch = transcript.match(/(?:company:|confirmed:|we are)\s*([A-Z][A-Za-z\s&]+(?:LLC|Inc|Corp|Co\.?)?)/);
  if (nameMatch) v2.company_name = nameMatch[1].trim();
}

// Compute diff
const changes = [];
function diff(o, n, p) {
  p = p || '';
  const keys = new Set([...Object.keys(o || {}), ...Object.keys(n || {})]);
  for (const k of keys) {
    const skip = ['_extraction_method','created_at','updated_at','version','pipeline_source','account_id'];
    if (skip.includes(k)) continue;
    const fp = p ? p + '.' + k : k;
    if (typeof o[k] === 'object' && typeof n[k] === 'object' && o[k] && n[k] && !Array.isArray(o[k])) {
      diff(o[k], n[k], fp);
    } else if (JSON.stringify(o[k]) !== JSON.stringify(n[k])) {
      changes.push({ field: fp, change_type: !o[k] ? 'added' : !n[k] ? 'removed' : 'modified', old_value: o[k], new_value: n[k] });
    }
  }
}
diff(v1, v2);

v2.version = 'v2';
v2.updated_at = new Date().toISOString();
v2.pipeline_source = 'onboarding_call';

// Save v2
const v2Dir = path.join('/home/user/clara-automation/outputs/accounts', accountId, 'v2');
fs.mkdirSync(v2Dir, { recursive: true });
fs.writeFileSync(path.join(v2Dir, 'memo.json'), JSON.stringify(v2, null, 2));

// Generate changelog
const changelogLines = [
  `# Changelog: ${accountId}`,
  `## v1 → v2`,
  `Generated: ${new Date().toISOString()}`,
  `Total changes: ${changes.length}`,
  '',
  '## Changes',
  ''
];
for (const c of changes) {
  changelogLines.push(`### \`${c.field}\` [${c.change_type}]`);
  if (c.old_value !== null && c.old_value !== undefined) changelogLines.push(`- Before: \`${JSON.stringify(c.old_value)}\``);
  if (c.new_value !== null && c.new_value !== undefined) changelogLines.push(`- After: \`${JSON.stringify(c.new_value)}\``);
  changelogLines.push('');
}

fs.writeFileSync(path.join(v2Dir, 'changes.md'), changelogLines.join('\n'));
fs.writeFileSync(path.join(v2Dir, 'changes.json'), JSON.stringify({ account_id: accountId, changes, generated_at: new Date().toISOString() }, null, 2));

return { json: { status: 'success', account_id: accountId, change_count: changes.length, changes } };
